function.body:
-- Logistice v_ResultStr VARCHAR2(2000):=''; v_Message VARCHAR2(2000):=''; v_msg VARCHAR2(2000):=''; v_Result NUMBER:=1; -- 0=failure v_Record_ID VARCHAR2(32); v_Detail_ID VARCHAR2(32); v_User_ID VARCHAR2(32):='0'; v_payment_schedule_id VARCHAR2(32); v_Lineno NUMBER:=10; -- 0=failure v_quote NUMBER; vOutstandingAmt NUMBER; -- 0=failure
TYPE RECORD IS REF CURSOR; Cur_Parameter RECORD; Cur_Head RECORD; Cur_Lines RECORD;
BEGIN
DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || P_Instance_ID); v_ResultStr:='PInstanceNotFound'; AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'Y', NULL, NULL);
BEGIN --BODY -- Get Parameters v_ResultStr:='ReadingParameters'; FOR Cur_Parameter IN ( SELECT i.Record_ID, i.AD_User_ID, p.ParameterName, p.P_String, p.P_Number, p.P_Date FROM AD_PInstance i LEFT JOIN AD_PInstance_Para p ON i.AD_PInstance_ID = p.AD_PInstance_ID WHERE i.AD_PInstance_ID = P_Instance_ID ORDER BY p.SeqNo ) LOOP v_Record_ID := Cur_Parameter.Record_ID; v_User_ID := Cur_Parameter.AD_User_ID; END LOOP; -- Get Parameter
-- Consultamos los datos de la cabecera de la trx SELECT ad_org_id, c_bpartner_id, datefrom, dateto, valuefrom, valueto, readytoprocess INTO Cur_Head FROM sdcc_daily_clossing WHERE sdcc_daily_clossing_id = v_Record_ID;
-- Verificar si el SELECT no encontró resultados IF NOT FOUND THEN v_msg := 'No se encontraron resultados para sdcc_daily_clossing_id '|| v_Record_ID; RAISE_APPLICATION_ERROR(-20000, v_msg); END IF;
-- Controlamos el check Listo para procesar -- 'Y' procesa normalmente IF Cur_Head.readytoprocess = 'Y' THEN
Delete from sdcc_daily_clossingline where sdcc_daily_clossing_id = v_Record_ID;
Delete from sdcc_daily_clossing_payment where sdcc_daily_clossing_id = v_Record_ID;
FOR Cur_Lines IN ( SELECT ci.ad_client_id, ci.ad_org_id, ci.createdby, ci.OutstandingAmt, ci.totalpaid, ci.c_bpartner_id, ci.c_invoice_id, ci.documentno, sum(psd.amount) AS totallines, grandtotal FROM c_invoice ci JOIN fin_payment_schedule ps ON ps.c_invoice_id = ci.c_invoice_id JOIN fin_payment_scheduledetail psd ON psd.fin_payment_schedule_invoice = ps.fin_payment_schedule_id WHERE issotrx = 'Y' AND ci.docstatus = 'CO' AND ci.OutstandingAmt <= Cur_Head.valueto AND ci.OutstandingAmt >= Cur_Head.valuefrom AND ad_isorgincluded (ci.ad_org_id, Cur_Head.ad_org_id, ci.ad_client_id) > 0 AND (ci.c_bpartner_id = Cur_Head.c_bpartner_id OR Cur_Head.c_bpartner_id IS NULL) AND TRUNC(ci.DateInvoiced) BETWEEN TRUNC(Cur_Head.datefrom) AND TRUNC(Cur_Head.dateto) GROUP BY ci.c_invoice_id -- HAVING -- sum(psd.amount) <> grandtotal ) LOOP -- Consultamos el plan de pagos disponible para asociar el detalle pendiente WITH lines_outstandingAmt AS ( SELECT fin_payment_schedule_id, expecteddate, ROW_NUMBER() OVER (ORDER BY expecteddate) AS rn FROM fin_payment_schedule ps WHERE ps.c_invoice_id = Cur_Lines.c_invoice_id AND ps.OutstandingAmt <> 0 ) SELECT fin_payment_schedule_id INTO v_payment_schedule_id FROM lines_outstandingAmt WHERE rn = 1;
-- Verificar si el SELECT no encontró resultados IF NOT FOUND THEN v_msg := 'No se encontro un plan de pagos con monto pendiente para la factura: '|| Cur_Lines.documentno; RAISE_APPLICATION_ERROR(-20000, v_msg); END IF;
IF COALESCE(Cur_Lines.totallines, 0) <> COALESCE(Cur_Lines.grandtotal, 0) THEN
v_Detail_ID := get_uuid(); -- Creamos la linea por el valor pendiente INSERT INTO fin_payment_scheduledetail (fin_payment_scheduledetail_id, ad_client_id, ad_org_id, createdby, updatedby, fin_payment_schedule_invoice, amount, c_bpartner_id) VALUES (v_Detail_ID, Cur_Lines.ad_client_id, Cur_Lines.ad_org_id, Cur_Lines.createdby, Cur_Lines.createdby, v_payment_schedule_id, Cur_Lines.OutstandingAmt, Cur_Lines.c_bpartner_id); ELSE SELECT fin_payment_scheduledetail_id INTO v_Detail_ID FROM fin_payment_scheduledetail WHERE fin_payment_schedule_invoice = v_payment_schedule_id AND fin_payment_detail_id IS NULL; END IF;
INSERT INTO sdcc_daily_clossingline (sdcc_daily_clossingline_id, ad_client_id, ad_org_id, createdby, updatedby, line, documentno, c_invoice_id, sdcc_daily_clossing_id,detailtrx, totalpaid, grandTotalAmount, outstandingAmount) VALUES (get_uuid (), Cur_Lines.ad_client_id, Cur_Lines.ad_org_id, Cur_Lines.createdby, Cur_Lines.createdby, v_Lineno, Cur_Lines.documentno, Cur_Lines.c_invoice_id, v_Record_ID, v_Detail_ID, Cur_Lines.totalpaid, Cur_Lines.grandtotal, Cur_Lines.OutstandingAmt);
v_Lineno := v_Lineno + 10;
UPDATE sdcc_daily_clossing SET executepayment = 'PR' WHERE sdcc_daily_clossing_id = v_Record_ID;
END LOOP; -- Get Cur_Lines
ELSE -- 'N' mantiene el estado de la cabecera en Cargar Lineas.
Delete from sdcc_daily_clossingline where sdcc_daily_clossing_id = v_Record_ID;
Delete from sdcc_daily_clossing_payment where sdcc_daily_clossing_id = v_Record_ID;
FOR Cur_Lines IN ( SELECT ci.ad_client_id, ci.ad_org_id, ci.createdby, ci.OutstandingAmt, ci.totalpaid, ci.c_bpartner_id, ci.c_invoice_id, ci.documentno, sum(psd.amount) AS totallines, grandtotal FROM c_invoice ci JOIN fin_payment_schedule ps ON ps.c_invoice_id = ci.c_invoice_id JOIN fin_payment_scheduledetail psd ON psd.fin_payment_schedule_invoice = ps.fin_payment_schedule_id WHERE issotrx = 'Y' AND ci.docstatus = 'CO' AND ci.OutstandingAmt <= Cur_Head.valueto AND ci.OutstandingAmt >= Cur_Head.valuefrom AND ad_isorgincluded (ci.ad_org_id, Cur_Head.ad_org_id, ci.ad_client_id) > 0 AND (ci.c_bpartner_id = Cur_Head.c_bpartner_id OR Cur_Head.c_bpartner_id IS NULL) AND TRUNC(ci.DateInvoiced) BETWEEN TRUNC(Cur_Head.datefrom) AND TRUNC(Cur_Head.dateto) GROUP BY ci.c_invoice_id -- HAVING -- sum(psd.amount) <> grandtotal ) LOOP -- Consultamos el plan de pagos disponible para asociar el detalle pendiente WITH lines_outstandingAmt AS ( SELECT fin_payment_schedule_id, expecteddate, ROW_NUMBER() OVER (ORDER BY expecteddate) AS rn FROM fin_payment_schedule ps WHERE ps.c_invoice_id = Cur_Lines.c_invoice_id AND ps.OutstandingAmt <> 0 ) SELECT fin_payment_schedule_id INTO v_payment_schedule_id FROM lines_outstandingAmt WHERE rn = 1;
-- Verificar si el SELECT no encontró resultados IF NOT FOUND THEN v_msg := 'No se encontro un plan de pagos con monto pendiente para la factura: '|| Cur_Lines.documentno; RAISE_APPLICATION_ERROR(-20000, v_msg); END IF;
IF COALESCE(Cur_Lines.totallines, 0) <> COALESCE(Cur_Lines.grandtotal, 0) THEN
v_Detail_ID := get_uuid(); -- Creamos la linea por el valor pendiente INSERT INTO fin_payment_scheduledetail (fin_payment_scheduledetail_id, ad_client_id, ad_org_id, createdby, updatedby, fin_payment_schedule_invoice, amount, c_bpartner_id) VALUES (v_Detail_ID, Cur_Lines.ad_client_id, Cur_Lines.ad_org_id, Cur_Lines.createdby, Cur_Lines.createdby, v_payment_schedule_id, Cur_Lines.OutstandingAmt, Cur_Lines.c_bpartner_id); ELSE SELECT fin_payment_scheduledetail_id INTO v_Detail_ID FROM fin_payment_scheduledetail WHERE fin_payment_schedule_invoice = v_payment_schedule_id AND fin_payment_detail_id IS NULL; END IF;
INSERT INTO sdcc_daily_clossingline (sdcc_daily_clossingline_id, ad_client_id, ad_org_id, createdby, updatedby, line, documentno, c_invoice_id, sdcc_daily_clossing_id,detailtrx, totalpaid, grandTotalAmount, outstandingAmount) VALUES (get_uuid (), Cur_Lines.ad_client_id, Cur_Lines.ad_org_id, Cur_Lines.createdby, Cur_Lines.createdby, v_Lineno, Cur_Lines.documentno, Cur_Lines.c_invoice_id, v_Record_ID, v_Detail_ID, Cur_Lines.totalpaid, Cur_Lines.grandtotal, Cur_Lines.OutstandingAmt);
v_Lineno := v_Lineno + 10;
END LOOP; -- Get Cur_Lines
END IF;
DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished ' || v_Message); AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'N', v_Result, v_Message);
RETURN; END; --BODY
EXCEPTION WHEN OTHERS THEN v_ResultStr:= '@ERROR=' || SQLERRM; DBMS_OUTPUT.PUT_LINE( v_ResultStr) ; ROLLBACK; AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'N', 0, v_ResultStr); END SDCC_GENERATE_SCHEDULEDETAIL
